named.conf.options:
acl "trusted" {
        192.168.5.0/24;    
        192.168.5.12; #ns1
        192.168.5.13; #ns2
};

options {
        directory "/var/cache/bind";
        recursion yes;                 # enables recursive queries
        allow-recursion { trusted; };  # allows recursive queries from "trusted" clients
        listen-on { 192.168.5.12; };
        allow-query { trusted; };
        allow-transfer { key transfert-key; };
        notify explicit;
	also-notify { 192.168.5.13; }; #Notifier ns2

        forwarders {
                8.8.8.8;
                8.8.4.4;
        };

        //response-policy {
        //     zone "rpz.intra";
        //     zone "rpz.urlhaus.zone";
        //};

        dnssec-validation auto;
        listen-on-v6 { none; }; #Désactiver IPv6 si non utilisé
};

logging {
  channel query_log {
    file "/var/log/named/data/query.log" versions 3 size 10m;
    severity info;
    print-time yes;
    print-severity yes;
    print-category yes;
  };
  category queries { query_log; };

  channel error_log {
    file "/var/log/named/data/error.log" versions 3 size 10m;
    severity debug;
    print-time yes;
    print-severity yes;
    print-category yes;
  };
  category default { error_log; };

  channel notification_log {
    file "/var/log/named/data/notification.log" versions 3 size 10m;
    severity debug;
    print-time yes;
    print-severity yes;
    print-category yes;
  };
  category notify { notification_log; };

  channel rate_limiting_log {
    file "/var/log/named/data/rate_limiting.log" versions 3 size 10m;
    severity debug;
    print-time yes;
    print-severity yes;
    print-category yes;
  };
  category rate-limit { rate_limiting_log; };

  channel client_security_log {
     file "/var/log/named/data/security.log" versions 3 size 30m;
     severity dynamic;
     print-time yes;
  };
  category security { client_security_log; };

// channel rpz_log {
