//    severity info;
//    print-time yes;
//    print-category yes;
//    print-severity yes;
//    };
//  category rpz { rpz_log; };

};

named.conf.local:
//
// Do any local configuration here
//

// Consider adding the 1918 zones here, if they are not used in your
// organization
//include "/etc/bind/zones.rfc1918";

server 192.168.5.13 {
    keys { transfert-key; };  # Utiliser la clé pour NS2
};

zone "smam.intra" IN {
    type master;
    file "/var/cache/bind/zones/forward/smam.intra";
    allow-transfer { key transfert-key;  };
    also-notify { 192.168.5.13;  };
};

zone "5.168.192.in-addr.arpa" IN {
    type master;
    file "/var/cache/bind/zones/reverse/smam.intra";
    allow-transfer { key transfert-key;  };
    also-notify { 192.168.5.13;  };
};

named.conf:
// This is the primary configuration file for the BIND DNS server named.
//
// Please read /usr/share/doc/bind9/README.Debian for information on the
// structure of BIND configuration files in Debian, *BEFORE* you customize
// this configuration file.
//
// If you are just adding zones, please do that in /etc/bind/named.conf.local

include "/etc/bind/named.conf.options";
include "/etc/bind/named.conf.local";
include "/etc/bind/named.conf.default-zones";

include "/etc/bind/named.conf.acls";

include "/etc/bind/named.conf.keys";
